+	} else if opts.SkipDatabase || !manifest.Contents.Database.Included {
+		result.OptionalActions = append(result.OptionalActions, OptionalAction{
+			Name:   "database",
+			Action: "skip",
+			Reason: func() string {
+				if !manifest.Contents.Database.Included {
+					return "not in bundle"
