+// TestSyncStatus tests the SyncStatus struct and GetSyncStatus.
+func TestSyncStatus(t *testing.T) {
+	tmpDir := t.TempDir()
+
+	// Set XDG_DATA_HOME for sync state
+	oldXDG := os.Getenv("XDG_DATA_HOME")
+	os.Setenv("XDG_DATA_HOME", tmpDir)
